int main(int argc, char *argv[])
{
    IMAGE *in;
    TIFF *out;
    int c;
#if !HAVE_DECL_OPTARG
    extern int optind;
    extern char *optarg;
#endif

    while ((c = getopt(argc, argv, "c:p:r:")) != -1)
        switch (c)
        {
            case 'c': /* compression scheme */
                if (!processCompressOptions(optarg))
                    usage();
                break;
            case 'f': /* fill order */
                if (streq(optarg, "lsb2msb"))
                    fillorder = FILLORDER_LSB2MSB;
                else if (streq(optarg, "msb2lsb"))
                    fillorder = FILLORDER_MSB2LSB;
                else
                    usage();
                break;
            case 'p': /* planar configuration */
                if (streq(optarg, "separate"))
                    config = PLANARCONFIG_SEPARATE;
                else if (streq(optarg, "contig"))
                    config = PLANARCONFIG_CONTIG;
                else
                    usage();
                break;
            case 'r': /* rows/strip */
                rowsperstrip = atoi(optarg);
                break;
            case '?':
                usage();
                /*NOTREACHED*/
        }
    if (argc - optind != 2)
        usage();
    in = iopen(argv[optind], "r");
    if (in == NULL)
        return (-1);
    out = TIFFOpen(argv[optind + 1], "w");
    if (out == NULL)
        return (-2);
    TIFFSetField(out, TIFFTAG_IMAGEWIDTH, (uint32_t)in->xsize);
    TIFFSetField(out, TIFFTAG_IMAGELENGTH, (uint32_t)in->ysize);
    TIFFSetField(out, TIFFTAG_BITSPERSAMPLE, 8);
    TIFFSetField(out, TIFFTAG_COMPRESSION, compression);
    if (in->zsize == 1)
        photometric = PHOTOMETRIC_MINISBLACK;
    else
        photometric = PHOTOMETRIC_RGB;
    switch (compression)
    {
        case COMPRESSION_JPEG:
            if (photometric == PHOTOMETRIC_RGB &&
                jpegcolormode == JPEGCOLORMODE_RGB)
                photometric = PHOTOMETRIC_YCBCR;
            TIFFSetField(out, TIFFTAG_JPEGQUALITY, quality);
            TIFFSetField(out, TIFFTAG_JPEGCOLORMODE, jpegcolormode);
            break;
        case COMPRESSION_LZW:
        case COMPRESSION_ADOBE_DEFLATE:
        case COMPRESSION_DEFLATE:
            if (predictor != 0)
                TIFFSetField(out, TIFFTAG_PREDICTOR, predictor);
            break;
    }
    TIFFSetField(out, TIFFTAG_PHOTOMETRIC, photometric);
    if (fillorder != 0)
        TIFFSetField(out, TIFFTAG_FILLORDER, fillorder);
    TIFFSetField(out, TIFFTAG_ORIENTATION, ORIENTATION_TOPLEFT);
    TIFFSetField(out, TIFFTAG_SAMPLESPERPIXEL, in->zsize);
    if (in->zsize > 3)
    {
        uint16_t v[1];
        v[0] = EXTRASAMPLE_UNASSALPHA;
        TIFFSetField(out, TIFFTAG_EXTRASAMPLES, 1, v);
    }
    TIFFSetField(out, TIFFTAG_MINSAMPLEVALUE, (uint16_t)in->min);
    TIFFSetField(out, TIFFTAG_MAXSAMPLEVALUE, (uint16_t)in->max);
    TIFFSetField(out, TIFFTAG_PLANARCONFIG, config);
    if (config != PLANARCONFIG_SEPARATE)
        TIFFSetField(out, TIFFTAG_ROWSPERSTRIP,
                     TIFFDefaultStripSize(out, rowsperstrip));
    else /* force 1 row/strip for library limitation */
        TIFFSetField(out, TIFFTAG_ROWSPERSTRIP, 1L);
    if (in->name[0] != '\0')
        TIFFSetField(out, TIFFTAG_IMAGEDESCRIPTION, in->name);
    if (config == PLANARCONFIG_CONTIG)
        cpContig(in, out);
    else
        cpSeparate(in, out);
    (void)iclose(in);
    (void)TIFFClose(out);
    return (0);
}

static int processCompressOptions(char *opt)
{
    if (streq(opt, "none"))
        compression = COMPRESSION_NONE;
    else if (streq(opt, "packbits"))
        compression = COMPRESSION_PACKBITS;
    else if (strneq(opt, "jpeg", 4))
    {
        char *cp = strchr(opt, ':');

        defcompression = COMPRESSION_JPEG;
        while (cp)
        {
            if (isdigit((int)cp[1]))
                quality = atoi(cp + 1);
            else if (cp[1] == 'r')
                jpegcolormode = JPEGCOLORMODE_RAW;
            else
                usage();

            cp = strchr(cp + 1, ':');
        }
    }
    else if (strneq(opt, "lzw", 3))
    {
        char *cp = strchr(opt, ':');
        if (cp)
            predictor = atoi(cp + 1);
        compression = COMPRESSION_LZW;
    }
    else if (strneq(opt, "zip", 3))
    {
        char *cp = strchr(opt, ':');
        if (cp)
            predictor = atoi(cp + 1);
        compression = COMPRESSION_ADOBE_DEFLATE;
    }
    else
        return (0);
    return (1);
}

static int cpContig(IMAGE *in, TIFF *out)
{
    tdata_t buf = _TIFFmalloc(TIFFScanlineSize(out));
    short *r = NULL;
    int x, y;

    if (in->zsize == 3)
    {
        short *g, *b;

        r = (short *)_TIFFmalloc(3 * in->xsize * sizeof(short));
        g = r + in->xsize;
        b = g + in->xsize;
        for (y = in->ysize - 1; y >= 0; y--)
        {
            uint8_t *pp = (uint8_t *)buf;

            getrow(in, r, y, 0);
            getrow(in, g, y, 1);
            getrow(in, b, y, 2);
            for (x = 0; x < in->xsize; x++)
            {
                pp[0] = r[x];
                pp[1] = g[x];
                pp[2] = b[x];
                pp += 3;
            }
            if (TIFFWriteScanline(out, buf, in->ysize - y - 1, 0) < 0)
                goto bad;
        }
    }
    else if (in->zsize == 4)
    {
        short *g, *b, *a;

        r = (short *)_TIFFmalloc(4 * in->xsize * sizeof(short));
        g = r + in->xsize;
        b = g + in->xsize;
        a = b + in->xsize;
        for (y = in->ysize - 1; y >= 0; y--)
        {
            uint8_t *pp = (uint8_t *)buf;

            getrow(in, r, y, 0);
            getrow(in, g, y, 1);
            getrow(in, b, y, 2);
            getrow(in, a, y, 3);
            for (x = 0; x < in->xsize; x++)
            {
                pp[0] = r[x];
                pp[1] = g[x];
                pp[2] = b[x];
                pp[3] = a[x];
                pp += 4;
            }
            if (TIFFWriteScanline(out, buf, in->ysize - y - 1, 0) < 0)
                goto bad;
        }
    }
    else
    {
        uint8_t *pp = (uint8_t *)buf;

        r = (short *)_TIFFmalloc(in->xsize * sizeof(short));
        for (y = in->ysize - 1; y >= 0; y--)
        {
            getrow(in, r, y, 0);
            for (x = in->xsize - 1; x >= 0; x--)
                pp[x] = r[x];
            if (TIFFWriteScanline(out, buf, in->ysize - y - 1, 0) < 0)
                goto bad;
        }
    }
    if (r)
        _TIFFfree(r);
    _TIFFfree(buf);
    return (1);
bad:
    if (r)
        _TIFFfree(r);
    _TIFFfree(buf);
    return (0);
}

static int cpSeparate(IMAGE *in, TIFF *out)
{
    tdata_t buf = _TIFFmalloc(TIFFScanlineSize(out));
    short *r = (short *)_TIFFmalloc(in->xsize * sizeof(short));
    uint8_t *pp = (uint8_t *)buf;
    int x, y, z;

    for (z = 0; z < in->zsize; z++)
    {
        for (y = in->ysize - 1; y >= 0; y--)
        {
            getrow(in, r, y, z);
            for (x = 0; x < in->xsize; x++)
                pp[x] = r[x];
            if (TIFFWriteScanline(out, buf, in->ysize - y - 1, z) < 0)
                goto bad;
        }
    }
    _TIFFfree(r);
    _TIFFfree(buf);
    return (1);
bad:
    _TIFFfree(r);
    _TIFFfree(buf);
    return (0);
}

static void usage(void)
{
    char buf[BUFSIZ];
    int i;

    setbuf(stderr, buf);
    for (i = 0; stuff[i] != NULL; i++)
        fprintf(stderr, "%s\n", stuff[i]);
    exit(-1);
}
